INSERT INTO `bonus_surveys` VALUES (19,'userid_4fec82c7eea61','Dinobot','https://docs.google.com/forms/d/e/1FAIpQLSeI9AZ0WGIs5eEIuwlz9rMbax6ck79cKWDIRZW0e7Wwk1UQtMA/viewform?usp=pp_url&entry.1711341715=user_token_here','Me Grimlock, leader of Dinobots, have official mission statement! It very professional. Listen close:\r\n\'WE FIND WEAK THINGS. WE CRUNCH THEM. THEN WE FIND BIGGER THINGS... AND CRUNCH THEM TOO. IF IT NOT CRUNCHABLE, WE STOMP UNTIL IT IS.\'','2026-01-26 00:00:00','2026-02-06 00:00:00','pending_approval','2026-01-26 02:17:50','2026-01-26 02:17:50'),(20,'userid_4fec82c7eea61','Decipticon','https://docs.google.com/forms/d/e/1FAIpQL1SeI9AZ0WGIs5eEIuwlz9rMbax6ck79cKWDIRZW0e7WwkUQtMA/viewform?usp=pp_url&entry.1711341715=user_token_here','Crush the autobots. Reclaim Cybertron. Take rightful ownership of Matrix of Leadership','2026-01-26 00:00:00','2026-02-06 00:00:00','pending_approval','2026-01-26 03:07:56','2026-01-26 03:07:56'),(21,'userid_4fec82c7eea61','Autobot','https://docs.google.com/forms/d/e/1FAIpQLSeI9AZ0WGIs5eEIuwlz9rMb1ax6ck79cKWDIRZW0e7WwkUQtMA/viewform?usp=pp_url&entry.1711341715=user_token_here','Protect the Earth. Protect Cybertron. Protect Humans.','2026-01-26 00:00:00','2026-02-06 00:00:00','pending_approval','2026-01-26 03:20:21','2026-01-26 03:20:21'),(22,'userid_4fec82c7eea61','Cybertron','https://docs.google.com/forms/d/e/1FAIpQLSeI9AZ0WGIs5eEIuwlz9rMbax6ck79cKWDIRZW0e7WwkU1QtMA/viewform?usp=pp_url&entry.1711341715=user_token_here','Peace on Cybertron. Settle Autobot and Decepticon differences. Enough Energon for all','2026-01-27 00:00:00','2026-02-14 00:00:00','pending_approval','2026-01-27 08:15:13','2026-01-27 08:15:13'),(23,'userid_4fec82c7eea61','Optimus Prime','https://docs.google.com/forms/d/e/1FAIpQLSeI9AZ0WGIs5eEIuwlz9rMbax6ck79cKWDIRZW0e71WwkUQtMA/viewform?usp=pp_url&entry.1711341715=user_token_here','To restore peace across the universe and to stand up against tyranny wherever it flourishes.','2026-01-29 00:00:00','2026-02-14 00:00:00','active','2026-01-29 10:09:02','2026-01-30 05:01:45'),(24,'userid_4fec82c7eea61','Logitech Support Site Survey','https://docs.google.com/forms/d/e/1FAIpQLScP37QGlXiUyryFrBobY0b6V62RZkmA83rBQJ_lp52BIWhdOQ/viewform?usp=pp_url&entry.1711341715=user_token_here','Evaluation of the current capabilities of our support website and to identify any gaps or needs that are not being addressed.','2026-03-09 00:00:00','2026-04-10 00:00:00','active','2026-01-31 05:11:10','2026-01-31 05:21:34'),(25,'userid_4fec82c7eea61','Uncanny Avengers','https://docs.google.com/forms/d/e/1FAIpQLSeI9A1Z0WGIs5eEIuwlz9rMbax6ck79cKWDIRZW0e7WwkUQtMA/viewform?usp=pp_url&entry.1711341715=user_token_here','Find out about you','2026-02-12 00:00:00','2026-02-18 00:00:00','active','2026-02-05 07:57:41','2026-03-05 05:54:22'),(26,'userid_4fec82c7eea61','Cortado','https://docs.google.com/forms/d/e/1FAIpQLSc1QtXn_2dkgUb6tx69HTUl7xEyLDT5y7pxPVkyGLI2xYPs2Q/viewform?usp=pp_url&entry.1711341715=user_token_here','To determine market readiness of keys to go 2','2026-02-28 00:00:00','2026-03-31 00:00:00','active','2026-02-11 02:07:07','2026-02-11 02:35:36');
