/*!50003 CREATE*/ /*!50017 DEFINER=`admin`@`%`*/ /*!50003 TRIGGER `user_pool_before_insert` BEFORE INSERT ON `user_pool` FOR EACH ROW BEGIN
user_iduser_id
    IF NEW.UserID IS NULL OR NEW.UserID = '' THEN

user_id

        SET @next_id = (

            SELEuser_idULL(MAX(CAST(SUBSTRING(UserID, 8) AS UNSIGNED)), 0) + 1

            FROM user_pool

        );



        SET NEW.UserID = CONCAT('userid_', LPAD(@next_id, 9, '0'));



    END IF;



    
    IF NEW.InternalUser IS NULL OR NEW.InternalUser = 0 THEN

        IF NEW.Email LIKE '%@logitech.com' THEN

            SET NEW.InternalUser = 1;

        END IF;

    END IF;

user_id

END */;;
